// Verify the weather API returns data with all fields needed for map indicators
async function testWeatherApiDataShape() {
  const resp = await fetch('http://localhost:3001/api/weather?lat=41.39&lon=2.17');
  assertEquals(resp.status, 200, 'Weather API should return 200');

  const data = await resp.json();
  assert(data.current, 'Response should have current weather');

  // Fields needed by updateMapIndicators
  assert(typeof data.current.temperature === 'number', 'Should have temperature');
  assert(typeof data.current.pressure === 'number', 'Should have pressure');
  assert(typeof data.current.windSpeed === 'number', 'Should have windSpeed');
  assert(typeof data.current.windDirection === 'number', 'Should have windDirection');

  // Hourly data for timeline
  assert(Array.isArray(data.hourly), 'Should have hourly array');
  assert(data.hourly.length > 0, 'Hourly array should not be empty');

  var h = data.hourly[0];
  assert(typeof h.temperature === 'number', 'Hourly should have temperature');
  assert(typeof h.pressure === 'number', 'Hourly should have pressure');
  assert(typeof h.windSpeed === 'number', 'Hourly should have windSpeed');
}
